using System.Text.RegularExpressions;
using Microsoft.EntityFrameworkCore;
using STOTOP.Infrastructure.Data;

namespace STOTOP.WebAPI.Data.Seeders;

public static class SystemSeeder
{
    private const string Module = "System";

    public static void Migrate(STOTOPDbContext ctx)
    {
        var steps = new List<MigrationStep>
        {
            new(1, "数据库基线 (2026-05-26)", MigrateV1),
        };
        MigrationRunner.RunMigrations(ctx, Module, steps);
    }

    private static void MigrateV1(STOTOPDbContext ctx)
    {
        if (!SeederHelper.IsSqlServer(ctx)) return;

        // 1. 初始化组织类型（必须在组织架构之前）
        BasicDataSeeder.EnsureOrgTypes(ctx, true);

        // 2. 执行压缩的种子数据 SQL（SYS组织架构、SYS角色、SYS用户、SYS功能权限、SYS用户角色）
        var sql = SeederHelper.DecodeGzipBase64(
            SqlChunk0, SqlChunk1, SqlChunk2, SqlChunk3,
            SqlChunk4, SqlChunk5, SqlChunk6, SqlChunk7,
            SqlChunk8, SqlChunk9, SqlChunk10, SqlChunk11, SqlChunk12);

        // 按 GO 批处理分隔符拆分并逐批执行
        var batches = Regex.Split(sql, @"^\s*GO\s*$", RegexOptions.Multiline);
        foreach (var batch in batches)
        {
            var trimmed = batch.Trim();
            if (string.IsNullOrEmpty(trimmed)) continue;
            SeederHelper.ExecuteRawSql(ctx, trimmed);
        }

        // 3. admin 用户关联所有可切换组织
        EnsureAdminSwitchableOrgs(ctx);

        // 4. 注册系统管理权限并授予admin角色
        RegisterSystemPermissions(ctx);
    }

    /// <summary>
    /// 将 admin 用户关联到所有可切换组织，确保 admin 可在所有可切换组织间自由切换。
    /// 幂等：已存在的关联不重复插入，第一条记录设为主组织。
    /// </summary>
    private static void EnsureAdminSwitchableOrgs(STOTOPDbContext ctx)
    {
        SeederHelper.ExecuteRawSql(ctx, @"
DECLARE @adminUserId BIGINT;
SELECT @adminUserId = FID FROM [SYS用户] WHERE [F账号] = N'admin';

IF @adminUserId IS NOT NULL
BEGIN
    INSERT INTO [SYS用户组织] ([F用户ID], [F组织ID], [F是否主组织], [F状态], [F创建时间], [F更新时间])
    SELECT @adminUserId, o.FID, 0, 1, GETDATE(), GETDATE()
    FROM [SYS组织架构] o
    WHERE o.[F可切换] = CAST(1 AS BIT)
    AND NOT EXISTS (
        SELECT 1 FROM [SYS用户组织]
        WHERE [F用户ID] = @adminUserId AND [F组织ID] = o.FID
    );

    IF NOT EXISTS (
        SELECT 1 FROM [SYS用户组织]
        WHERE [F用户ID] = @adminUserId AND [F是否主组织] = 1
    )
    BEGIN
        UPDATE TOP(1) [SYS用户组织]
        SET [F是否主组织] = 1
        WHERE [F用户ID] = @adminUserId
        AND [F组织ID] = (
            SELECT MIN(o.FID) FROM [SYS组织架构] o
            WHERE o.[F可切换] = CAST(1 AS BIT)
        );
    END
END
");
    }

    /// <summary>
    /// 注册系统管理权限（模块→菜单→按钮）并自动授予 admin 角色。
    /// 幂等：所有 INSERT 均有 IF NOT EXISTS 保护，已存在的数据不会重复插入。
    /// </summary>
    private static void RegisterSystemPermissions(STOTOPDbContext ctx)
    {
        if (!SeederHelper.IsSqlServer(ctx)) return;

        ctx.Database.ExecuteSqlRaw(@"
-- 注册系统管理权限并授予admin角色

-- 1. 确保'权限管理'菜单存在
IF NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:permission' AND [F类型] = N'菜单')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    SELECT N'权限管理',N'sys:permission',N'菜单',[FID],5,1,1
    FROM [SYS功能权限] WHERE [F编码] = N'sys:manage' AND [F类型] = N'模块';

-- 2. 获取各菜单ID
DECLARE @UserMenuId BIGINT;
SELECT @UserMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'sys:user' AND [F类型] = N'菜单';

DECLARE @RoleMenuId BIGINT;
SELECT @RoleMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'sys:role' AND [F类型] = N'菜单';

DECLARE @PermissionMenuId BIGINT;
SELECT @PermissionMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'sys:permission' AND [F类型] = N'菜单';

DECLARE @OrgMenuId BIGINT;
SELECT @OrgMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'sys:org' AND [F类型] = N'菜单';

DECLARE @DingtalkMenuId BIGINT;
SELECT @DingtalkMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'sys:dingtalk' AND [F类型] = N'菜单';

DECLARE @AccountSetAuthMenuId BIGINT;
SELECT @AccountSetAuthMenuId = [FID] FROM [SYS功能权限] WHERE [F编码] = N'finance:accountset:auth' AND [F类型] = N'菜单';

-- 3. 插入按钮权限（幂等）
-- 用户管理按钮
IF @UserMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:user:create')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'创建用户',N'sys:user:create',N'按钮',@UserMenuId,1,1,1);

IF @UserMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:user:edit')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'编辑用户',N'sys:user:edit',N'按钮',@UserMenuId,2,1,1);

IF @UserMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:user:delete')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'删除用户',N'sys:user:delete',N'按钮',@UserMenuId,3,1,1);

IF @UserMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:user:reset-password')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'重置密码',N'sys:user:reset-password',N'按钮',@UserMenuId,4,1,1);

-- 角色管理按钮
IF @RoleMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:role:create')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'创建角色',N'sys:role:create',N'按钮',@RoleMenuId,1,1,1);

IF @RoleMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:role:edit')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'编辑角色',N'sys:role:edit',N'按钮',@RoleMenuId,2,1,1);

IF @RoleMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:role:delete')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'删除角色',N'sys:role:delete',N'按钮',@RoleMenuId,3,1,1);

IF @RoleMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:role:assign-permission')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'分配权限',N'sys:role:assign-permission',N'按钮',@RoleMenuId,4,1,1);

-- 权限管理按钮
IF @PermissionMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:permission:create')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'创建权限',N'sys:permission:create',N'按钮',@PermissionMenuId,1,1,1);

IF @PermissionMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:permission:edit')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'编辑权限',N'sys:permission:edit',N'按钮',@PermissionMenuId,2,1,1);

IF @PermissionMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:permission:delete')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'删除权限',N'sys:permission:delete',N'按钮',@PermissionMenuId,3,1,1);

-- 组织管理按钮
IF @OrgMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:org:create')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'创建组织',N'sys:org:create',N'按钮',@OrgMenuId,1,1,1);

IF @OrgMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:org:edit')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'编辑组织',N'sys:org:edit',N'按钮',@OrgMenuId,2,1,1);

IF @OrgMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:org:delete')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'删除组织',N'sys:org:delete',N'按钮',@OrgMenuId,3,1,1);

-- 钉钉集成按钮
IF @DingtalkMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'sys:dingtalk:manage')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'管理钉钉',N'sys:dingtalk:manage',N'按钮',@DingtalkMenuId,1,1,1);

-- 账套授权管理按钮（Finance模块下）
IF @AccountSetAuthMenuId IS NOT NULL AND NOT EXISTS (SELECT 1 FROM [SYS功能权限] WHERE [F编码] = N'accountset:authorization:manage')
    INSERT INTO [SYS功能权限] ([F名称],[F编码],[F类型],[F父ID],[F排序],[F状态],[F是否可见])
    VALUES (N'账套授权管理',N'accountset:authorization:manage',N'按钮',@AccountSetAuthMenuId,1,1,1);

-- 4. 为admin角色(F角色ID=1)关联所有新增的权限
INSERT INTO [SYS角色权限] ([F角色ID], [F权限ID])
SELECT 1, p.FID
FROM [SYS功能权限] p
WHERE p.[F编码] IN (
    N'sys:user:create', N'sys:user:edit', N'sys:user:delete', N'sys:user:reset-password',
    N'sys:role:create', N'sys:role:edit', N'sys:role:delete', N'sys:role:assign-permission',
    N'sys:permission:create', N'sys:permission:edit', N'sys:permission:delete',
    N'sys:org:create', N'sys:org:edit', N'sys:org:delete',
    N'sys:dingtalk:manage',
    N'accountset:authorization:manage'
)
AND NOT EXISTS (
    SELECT 1 FROM [SYS角色权限]
    WHERE [F角色ID] = 1 AND [F权限ID] = p.FID
);
");
    }

